/**
 * Convert kebab-case or snake_case to PascalCase
 * Example: "llm-call" => "LLMCall", "pattern_match" => "PatternMatch"
 */
export function toPascalCase(str: string): string {
  return str
    .split(/[-_]/)
    .map(word => {
      // Handle acronyms like "llm" => "LLM"
      if (word.length <= 3 && word.toLowerCase() === word) {
        return word.toUpperCase();
      }
      return word.charAt(0).toUpperCase() + word.slice(1);
    })
    .join('');
}

/**
 * Convert kebab-case or snake_case to camelCase
 * Example: "llm-call" => "llmCall", "pattern_match" => "patternMatch"
 */
export function toCamelCase(str: string): string {
  const pascal = toPascalCase(str);
  // Handle leading acronyms: "LLMCall" → "llmCall", "HTTPServer" → "httpServer"
  const match = pascal.match(/^([A-Z]+)([A-Z][a-z])/);
  if (match) {
    return match[1].toLowerCase() + pascal.slice(match[1].length);
  }
  return pascal.charAt(0).toLowerCase() + pascal.slice(1);
}

/**
 * Convert PascalCase or camelCase to kebab-case
 * Example: "LLMCall" => "llm-call", "patternMatch" => "pattern-match"
 */
export function toKebabCase(str: string): string {
  return str
    .replace(/([a-z0-9])([A-Z])/g, '$1-$2')
    .replace(/([A-Z]+)([A-Z][a-z])/g, '$1-$2')
    .toLowerCase();
}

/**
 * Convert PascalCase or camelCase to snake_case
 * Example: "LLMCall" => "llm_call", "patternMatch" => "pattern_match"
 */
export function toSnakeCase(str: string): string {
  return str
    .replace(/([a-z])([A-Z])/g, '$1_$2')
    .replace(/([A-Z])([A-Z][a-z])/g, '$1_$2')
    .toLowerCase();
}

/**
 * Convert kebab-case to snake_case for SQL table names
 * Example: "llm-call" => "llm_calls"
 */
export function toTableName(entityName: string): string {
  return toSnakeCase(entityName.replace(/-/g, '_')) + 's';
}

/**
 * Generate timestamp for migrations
 * Example: "001", "002", etc.
 */
export function getMigrationNumber(existingMigrations: string[]): string {
  const numbers = existingMigrations
    .map(m => parseInt(m.split('_')[0]))
    .filter(n => !isNaN(n));

  const next = numbers.length > 0 ? Math.max(...numbers) + 1 : 1;
  return String(next).padStart(3, '0');
}
